import { useEffect, useRef } from 'react';
import styles from './Gallery.module.css';
import gallery1 from '../assets/gallery-1.png';
import gallery2 from '../assets/gallery-2.png';
import gallery3 from '../assets/gallery-3.png';

interface GalleryItem {
  src: string;
  alt: string;
  label: string;
}

const baseItems: GalleryItem[] = [
  {
    src: gallery1,
    alt: 'Chopsticks lifting noodles from a bowl of ramen with soft egg and corn',
    label: 'Tonkotsu',
  },
  {
    src: gallery2,
    alt: 'A rich white broth ramen bowl with soft egg and scallion',
    label: 'Paitan Bowl',
  },
  {
    src: gallery3,
    alt: 'A vegetable forward ramen bowl with bok choy, corn and soft egg',
    label: 'Vegetable Shio',
  },
  {
    src: gallery1,
    alt: 'A dark broth ramen bowl topped with seaweed, greens and soft egg',
    label: 'Miso Ramen',
  },
    {
    src: gallery2,
    alt: 'A dark broth ramen bowl topped with seaweed, greens and soft egg',
    label: 'Sesame Ramen',
  },
];

const loopedItems = [...baseItems, ...baseItems, ...baseItems];

function Gallery(): JSX.Element {
  const trackRef = useRef<HTMLDivElement>(null);
  const setWidthRef = useRef(0);

  useEffect(() => {
    const track = trackRef.current;
    if (!track) return;

    const measureAndCenter = () => {
      const setWidth = track.scrollWidth / 3;
      setWidthRef.current = setWidth;

      // Start in the middle copy
      track.scrollLeft = setWidth;
    };

    // Wait until layout/images have settled
    requestAnimationFrame(measureAndCenter);

    window.addEventListener('resize', measureAndCenter);
    return () => window.removeEventListener('resize', measureAndCenter);
  }, []);

  useEffect(() => {
    const track = trackRef.current;
    if (!track) return;

    const handleWheel = (event: WheelEvent) => {
      const delta =
        Math.abs(event.deltaY) > Math.abs(event.deltaX)
          ? event.deltaY
          : event.deltaX;

      if (delta === 0) return;

      event.preventDefault();
      track.scrollLeft += delta;
    };

    track.addEventListener('wheel', handleWheel, { passive: false });

    return () => {
      track.removeEventListener('wheel', handleWheel);
    };
  }, []);

  const handleScroll = () => {
    const track = trackRef.current;
    if (!track) return;

    const setWidth = setWidthRef.current;
    const maxScroll = track.scrollWidth - track.clientWidth;

    // Wrapped too far left
    if (track.scrollLeft <= 1) {
      track.scrollLeft += setWidth;
    }

    // Wrapped too far right
    else if (track.scrollLeft >= maxScroll - 1) {
      track.scrollLeft -= setWidth;
    }
  };

  return (
    <section className={styles.gallery}>
      <div
        ref={trackRef}
        className={styles.grid}
        onScroll={handleScroll}
      >
        {loopedItems.map((item, index) => (
          <div className={styles.item} key={`${item.label}-${index}`}>
            <div className={styles.imageWrap}>
              <img src={item.src} alt={item.alt} />
            </div>
            <span className={styles.label}>{item.label}</span>
          </div>
        ))}
      </div>
    </section>
  );
}

export default Gallery;
